E2Helper.Descriptions["addMeshClip(e:vvnn)"]   = "Adds a physical clip to the entity, cutting away everything on the far side of the plane through vector1 (origin) facing vector2 (normal). number1 is keepMass (default 1), number2 is seal (default 1). Returns the new clip's ID, or 0 if it failed."
E2Helper.Descriptions["addMeshClip(e:vvn)"]    = "Alias of addMeshClip(e:vvnn) with seal defaulted to 1"
E2Helper.Descriptions["addMeshClip(e:vv)"]     = "Alias of addMeshClip(e:vvnn) with keepMass and seal defaulted to 1"
E2Helper.Descriptions["removeMeshClips(e:)"]   = "Removes all clips on the entity"
E2Helper.Descriptions["removeMeshClip(e:)"]    = "Alias of removeMeshClips(e:); removes all clips on the entity"
E2Helper.Descriptions["removeMeshClip(e:n)"]   = "Removes the clip on the entity with the given ID"
E2Helper.Descriptions["removeMeshClipByID(e:n)"] = "Alias of removeMeshClip(e:n); removes the clip on the entity with the given ID"
E2Helper.Descriptions["meshClipsLeft(e:)"]     = "Returns how many more clips can be added to the entity"
E2Helper.Descriptions["isMeshClipped(e:)"]     = "Returns 1 if the entity currently has any clips, 0 otherwise"
E2Helper.Descriptions["getMeshClips(e:)"]      = "Returns the entity's clips as an 'array' (table with numbers for keys) of tables, each with id, normal, distance, keepMass and seal. Empty if the entity has no clips."
